critical_node_replacements.Shuffle Pages:
const webhook = $('Receive Auto-Post Command').first().json || {};
const body = webhook.body || {};
const pageIds = Array.isArray(body.pageIds) ? [...body.pageIds] : [];

if (!pageIds.length) {
  throw new Error('No pageIds found in webhook body');
}

for (let i = pageIds.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [pageIds[i], pageIds[j]] = [pageIds[j], pageIds[i]];
}

return [{ json: { pageIds, webhookData: webhook } }];

critical_node_replacements.Build Page/Image Pairs:
const pageData = $('Shuffle Pages').first().json || {};
const pageIds = Array.isArray(pageData.pageIds) ? pageData.pageIds : [];
const webhookData = pageData.webhookData || {};
const images = $('Shuffle Images').all().map((item) => item.json);

if (!pageIds.length) {
  throw new Error('No pageIds found in Shuffle Pages');
}

if (!images.length) {
  throw new Error('No images found in Shuffle Images');
}

return pageIds.map((pageId, index) => ({
  json: {
    pageId,
    image: images[index % images.length],
    webhookData,
  },
}));

critical_node_replacements.Extract Page Token:
const accountsResponse = $('Get Page Access Token').first().json.body || {};
const pageAccounts = Array.isArray(accountsResponse.data) ? accountsResponse.data : [];

const sourceItems = $('Prepare Caption').all();

if (!pageAccounts.length) {
  throw new Error('No pages returned from Get Page Access Token');
}

if (!sourceItems.length) {
  throw new Error('No items returned from Prepare Caption');
}

const results = sourceItems.map((item) => {
  const source = item.json || {};
  const targetPageId = String(source.pageId || '').trim();

  if (!targetPageId) {
    throw new Error('Missing pageId in Prepare Caption item');
  }

  const matchedPage = pageAccounts.find((page) => String(page.id) === targetPageId);

  if (!matchedPage) {
    const availablePages = pageAccounts.map((page) => ({
      id: String(page.id),
      name: page.name || '',
    }));

    throw new Error(
      `Page ID ${targetPageId} not found in /me/accounts. Available pages: ${JSON.stringify(availablePages)}`
    );
  }

  return {
    json: {
      ...source,
      pageAccessToken: matchedPage.access_token,
      pageName: matchedPage.name || '',
      facebookPageId: String(matchedPage.id),
    },
  };
});

return results;
